<script setup lang="ts">
import { computed, onMounted, ref } from 'vue'
import type { SecretBackend, SecretProfileSummary } from '../../shared/contracts'
const profiles=ref<SecretProfileSummary[]>([]);const name=ref('Agnes primary');const provider=ref('agnes');const environmentVariable=ref('AGNES_API_KEY');const backend=ref<SecretBackend>('os');const secret=ref('');const password=ref('');const envFilePath=ref('');const busy=ref(false);const message=ref('');const snackbar=ref(false);const unlockTarget=ref<SecretProfileSummary>();const unlockPassword=ref('')
const backendItems=[{title:'OS secure storage',value:'os'},{title:'Session only',value:'session'},{title:'.env expert mode',value:'env'},{title:'Portable encrypted vault',value:'portable-vault'}]
const needsSecret=computed(()=>backend.value!=='env');const needsPassword=computed(()=>backend.value==='portable-vault')
async function refresh(){profiles.value=await window.mel.secrets.list()}
async function chooseEnv(){const path=await window.mel.chooseFile({title:'Select explicit .env file'});if(path)envFilePath.value=path}
function notify(text:string){message.value=text;snackbar.value=true}
async function save(){busy.value=true;try{await window.mel.secrets.save({name:name.value,provider:provider.value,environmentVariable:environmentVariable.value,backend:backend.value,secret:needsSecret.value?secret.value:undefined,password:needsPassword.value?password.value:undefined,envFilePath:backend.value==='env'?envFilePath.value:undefined});secret.value='';password.value='';notify('Credential profile saved.');await refresh()}catch(error){notify(error instanceof Error?error.message:String(error))}finally{busy.value=false}}
async function remove(profile:SecretProfileSummary){await window.mel.secrets.remove(profile.id);await refresh()}
function beginUnlock(profile:SecretProfileSummary){unlockTarget.value=profile;unlockPassword.value=''}
async function unlock(){if(!unlockTarget.value)return;busy.value=true;try{await window.mel.secrets.unlock(unlockTarget.value.id,unlockPassword.value);unlockTarget.value=undefined;unlockPassword.value='';notify('Portable vault unlocked for this session.');await refresh()}catch(error){notify(error instanceof Error?error.message:String(error))}finally{busy.value=false}}
async function lock(profile:SecretProfileSummary){await window.mel.secrets.lock(profile.id);await refresh()}
onMounted(refresh)
</script>
<template><v-card class="glass pa-6 mt-6"><div class="d-flex align-center ga-3 mb-5"><v-avatar color="secondary" variant="tonal" rounded="lg"><v-icon icon="mdi-key-chain-variant"/></v-avatar><div><div class="text-h6 font-weight-bold">Credential profiles</div><div class="text-body-2 text-medium-emphasis">Decrypted values never enter projects, Pinia, logs or durable job records.</div></div></div><v-row><v-col cols="12" md="4"><v-text-field v-model="name" label="Profile name" prepend-inner-icon="mdi-card-account-details-outline"/></v-col><v-col cols="12" md="4"><v-text-field v-model="provider" label="Provider" prepend-inner-icon="mdi-cloud-outline"/></v-col><v-col cols="12" md="4"><v-text-field v-model="environmentVariable" label="Environment variable" prepend-inner-icon="mdi-variable"/></v-col><v-col cols="12" md="4"><v-select v-model="backend" label="Storage backend" :items="backendItems" prepend-inner-icon="mdi-shield-key-outline"/></v-col><v-col v-if="needsSecret" cols="12" md="4"><v-text-field v-model="secret" type="password" label="Secret value" autocomplete="new-password" prepend-inner-icon="mdi-key-outline"/></v-col><v-col v-if="needsPassword" cols="12" md="4"><v-text-field v-model="password" type="password" label="Vault password (10+ chars)" autocomplete="new-password" prepend-inner-icon="mdi-lock-outline"/></v-col><v-col v-if="backend==='env'" cols="12" md="8"><v-text-field v-model="envFilePath" label="Explicit .env path" prepend-inner-icon="mdi-file-key-outline"><template #append-inner><v-btn icon="mdi-file-search-outline" size="small" variant="text" color="primary" @click.stop="chooseEnv"/></template></v-text-field></v-col></v-row><v-alert v-if="backend==='env'" color="warning" variant="tonal" density="compact" class="mb-4">This is plaintext-at-rest expert mode. The app will never silently create or fall back to this file.</v-alert><v-btn color="secondary" prepend-icon="mdi-content-save-lock-outline" :loading="busy" :disabled="!name||!provider||!environmentVariable||(needsSecret&&!secret)||(needsPassword&&password.length<10)||(backend==='env'&&!envFilePath)" @click="save">Save credential profile</v-btn><v-divider class="my-6"/><v-row v-if="profiles.length"><v-col v-for="profile in profiles" :key="profile.id" cols="12" md="6"><v-hover v-slot="{isHovering,props}"><v-card v-bind="props" variant="outlined" class="module-card pa-4" :class="{'is-hovered':isHovering}"><div class="d-flex justify-space-between"><div><div class="font-weight-bold">{{ profile.name }}</div><div class="text-caption text-medium-emphasis">{{ profile.provider }} · {{ profile.environmentVariable }}</div></div><v-chip :color="profile.unlocked?'success':'warning'" variant="tonal" size="small">{{ profile.unlocked?'Ready':'Locked' }}</v-chip></div><div class="d-flex flex-wrap ga-2 mt-3"><v-chip size="small" variant="outlined">{{ profile.backend }}</v-chip><v-chip size="small" :color="profile.secure?'success':'warning'" variant="tonal">{{ profile.secure?'secure':'expert/session' }}</v-chip></div><v-alert v-if="profile.warning" color="warning" variant="tonal" density="compact" class="mt-3">{{ profile.warning }}</v-alert><div class="d-flex ga-2 mt-4"><v-btn v-if="profile.backend==='portable-vault'&&!profile.unlocked" size="small" color="primary" prepend-icon="mdi-lock-open-outline" @click="beginUnlock(profile)">Unlock</v-btn><v-btn v-if="profile.backend==='portable-vault'&&profile.unlocked" size="small" variant="tonal" prepend-icon="mdi-lock-outline" @click="lock(profile)">Lock</v-btn><v-btn size="small" color="error" variant="text" prepend-icon="mdi-delete-outline" @click="remove(profile)">Remove</v-btn></div></v-card></v-hover></v-col></v-row><v-alert v-else color="info" variant="tonal">No credential profiles yet. Local and sample analysis remains available without API credentials.</v-alert><v-dialog :model-value="Boolean(unlockTarget)" max-width="480" @update:model-value="value=>{if(!value)unlockTarget=undefined}"><v-card class="pa-6"><div class="text-h6 font-weight-bold">Unlock {{ unlockTarget?.name }}</div><v-text-field v-model="unlockPassword" type="password" label="Portable vault password" autocomplete="current-password" class="mt-4"/><div class="d-flex justify-end ga-2"><v-btn variant="text" @click="unlockTarget=undefined">Cancel</v-btn><v-btn color="primary" :loading="busy" @click="unlock">Unlock</v-btn></div></v-card></v-dialog><v-snackbar v-model="snackbar" :timeout="5000">{{ message }}</v-snackbar></v-card></template>
